            // after create(). We cannot call Gdx.app.exit() directly from
            // create() because the main loop hasn't fully started yet; we
            // instead use a flag and handle it in render().
        }

        @Override
        public void render() {
            if (ticksRemaining > 0) {
                // Advance every actor's action queue by the fixed dt.
                for (Actor actor : actorList) {
                    actor.act(script.dt);
                }
                ticksRemaining--;
