    // -----------------------------------------------------------------------
    // Script parser
    // -----------------------------------------------------------------------

    static Script parseScript(String path) throws Exception {
        Script script = new Script();
        boolean dtSet = false;
        boolean ticksSet = false;

        List<String> lines = Files.readAllLines(Paths.get(path), StandardCharsets.UTF_8);
        int lineNo = 0;
        for (String raw : lines) {
            lineNo++;
            String line = raw.strip();
            if (line.isEmpty() || line.startsWith("#")) continue;

            // Split on one-or-more spaces/tabs.
            String[] tokens = line.split("[ \\t]+");
            if (tokens.length == 0) continue;

            String directive = tokens[0].toLowerCase(Locale.ROOT);

            switch (directive) {

                case "dt": {
                    if (tokens.length != 2)
                        throw new IllegalArgumentException("Line " + lineNo + ": 'dt' requires exactly 1 argument");
