    }

    // -----------------------------------------------------------------------
    // main
    // -----------------------------------------------------------------------

    public static void main(String[] args) throws Exception {
        if (args.length != 2) {
            System.err.println("Usage: gdx-stage-sim <script-path> <output-path>");
            System.exit(1);
        }

        String scriptPath = args[0];
        String outputPath = args[1];

        // Parse the script before starting the headless application so any
        // parse errors are reported immediately without spinning up libGDX.
        Script script = parseScript(scriptPath);

        // Configure the headless backend.
        HeadlessApplicationConfiguration config = new HeadlessApplicationConfiguration();
        // updatesPerSecond = 0 means: loop as fast as possible (no wall-clock pacing).
        config.updatesPerSecond = 0;

