                try (BufferedWriter bw = new BufferedWriter(
                        new OutputStreamWriter(
                                new FileOutputStream(outputPath, false),
                                StandardCharsets.UTF_8))) {
                    bw.write(sb.toString());
                }
            } catch (Exception e) {
                System.err.println("ERROR writing output file: " + e.getMessage());
                e.printStackTrace();
            }
        }
    }

    // -----------------------------------------------------------------------
    // Script parser
    // -----------------------------------------------------------------------

    static Script parseScript(String path) throws Exception {
        Script script = new Script();
        boolean dtSet = false;
        boolean ticksSet = false;

        List<String> lines = Files.readAllLines(Paths.get(path), StandardCharsets.UTF_8);
        int lineNo = 0;
        for (String raw : lines) {
            lineNo++;
            String line = raw.strip();
            if (line.isEmpty() || line.startsWith("#")) continue;

            // Split on one-or-more spaces/tabs.
            String[] tokens = line.split("[ \\t]+");
            if (tokens.length == 0) continue;

            String directive = tokens[0].toLowerCase(Locale.ROOT);

            switch (directive) {

                case "dt": {
                    if (tokens.length != 2)
                        throw new IllegalArgumentException("Line " + lineNo + ": 'dt' requires exactly 1 argument");
                    script.dt = Float.parseFloat(tokens[1]);
                    if (script.dt <= 0)
                        throw new IllegalArgumentException("Line " + lineNo + ": 'dt' must be > 0");
                    dtSet = true;
                    break;
                }

                case "ticks": {
                    if (tokens.length != 2)
                        throw new IllegalArgumentException("Line " + lineNo + ": 'ticks' requires exactly 1 argument");
                    script.ticks = Integer.parseInt(tokens[1]);
                    if (script.ticks < 0)
                        throw new IllegalArgumentException("Line " + lineNo + ": 'ticks' must be >= 0");
                    ticksSet = true;
                    break;
                }

                case "actor": {
                    if (!dtSet || !ticksSet)
                        throw new IllegalArgumentException("Line " + lineNo + ": 'actor' must appear after 'dt' and 'ticks'");
                    if (tokens.length != 4)
                        throw new IllegalArgumentException("Line " + lineNo + ": 'actor' requires exactly 3 arguments");
                    String id = tokens[1];
                    float x = Float.parseFloat(tokens[2]);
                    float y = Float.parseFloat(tokens[3]);
                    for (ActorSpec existing : script.actors) {
                        if (existing.id.equals(id))
                            throw new IllegalArgumentException("Line " + lineNo + ": duplicate actor id '" + id + "'");
                    }
                    script.actors.add(new ActorSpec(id, x, y));
                    break;
                }

                case "moveby": {
                    if (!dtSet || !ticksSet)
                        throw new IllegalArgumentException("Line " + lineNo + ": 'moveby' must appear after 'dt' and 'ticks'");
                    if (tokens.length != 5)
                        throw new IllegalArgumentException("Line " + lineNo + ": 'moveby' requires exactly 4 arguments");
                    String id = tokens[1];
                    float dx = Float.parseFloat(tokens[2]);
                    float dy = Float.parseFloat(tokens[3]);
                    float duration = Float.parseFloat(tokens[4]);
                    if (duration < 0)
                        throw new IllegalArgumentException("Line " + lineNo + ": 'moveby' duration must be >= 0");
                    if (script.moveBys.containsKey(id))
                        throw new IllegalArgumentException("Line " + lineNo + ": duplicate moveby for actor '" + id + "'");
                    // Verify the actor was declared.
                    boolean found = false;
                    for (ActorSpec a : script.actors) { if (a.id.equals(id)) { found = true; break; } }
                    if (!found)
                        throw new IllegalArgumentException("Line " + lineNo + ": moveby targets undeclared actor '" + id + "'");
                    script.moveBys.put(id, new MoveBySpec(id, dx, dy, duration));
                    break;
                }

                default:
                    throw new IllegalArgumentException("Line " + lineNo + ": unknown directive '" + directive + "'");
            }
        }

        if (!dtSet)    throw new IllegalArgumentException("Script is missing required 'dt' directive");
        if (!ticksSet) throw new IllegalArgumentException("Script is missing required 'ticks' directive");

        return script;
    }

    // -----------------------------------------------------------------------
    // main
    // -----------------------------------------------------------------------

    public static void main(String[] args) throws Exception {
        if (args.length != 2) {
            System.err.println("Usage: gdx-stage-sim <script-path> <output-path>");
            System.exit(1);
        }

        String scriptPath = args[0];
        String outputPath = args[1];

        // Parse the script before starting the headless application so any
        // parse errors are reported immediately without spinning up libGDX.
        Script script = parseScript(scriptPath);

        // Configure the headless backend.
        HeadlessApplicationConfiguration config = new HeadlessApplicationConfiguration();
        // updatesPerSecond = 0 means: loop as fast as possible (no wall-clock pacing).
        config.updatesPerSecond = 0;

        SimListener listener = new SimListener(script, outputPath);

        // HeadlessApplication extends Thread and starts itself in its constructor.
        HeadlessApplication app = new HeadlessApplication(listener, config);

        // Block until the headless loop thread finishes (i.e., after dispose() has
        // written the output file). This guarantees the file is flushed before exit.
        app.join();

        // libGDX may set a non-zero exit code via System.exit(); if we reach here
        // normally, exit cleanly with 0.
        System.exit(0);
    }
}

