                    dtSet = true;
                    break;
                }

                case "ticks": {
                    if (tokens.length != 2) {
                        throw new IllegalArgumentException(
                            "Line " + lineNo + ": 'ticks' requires exactly 1 argument");
                    }
                    script.ticks = Integer.parseInt(tokens[1]);
                    if (script.ticks < 0) {
                        throw new IllegalArgumentException(
                            "Line " + lineNo + ": 'ticks' must be >= 0");
                    }
                    ticksSet = true;
                    break;
                }

                case "actor": {
