                        if (existing.id.equals(id)) {
                            throw new IllegalArgumentException(
                                "Line " + lineNo + ": duplicate actor id '" + id + "'");
                        }
                    }
                    script.actors.add(new ActorSpec(id, x, y));
                    break;
                }

                case "moveby": {
                    if (!dtSet || !ticksSet) {
                        throw new IllegalArgumentException(
                            "Line " + lineNo + ": 'moveby' must appear after 'dt' and 'ticks'");
                    }
                    if (tokens.length != 5) {
